/**
 * checks files.md5 file to see if the file is from sugar
 * ONLY WORKS ON FILES
 *
 * @param string $path
 * @return bool
 */
public function sugarFileExists($path)
{
    static $md5 = array();
    if (empty($md5) && file_exists('files.md5')) {
        include('files.md5');
        $md5 = isset($md5_string) ? $md5_string : null;
    }
    if ($path[0] !== '.' || $path[1] !== '/') {
        $path = './' . $path;
    }
    if (isset($md5[$path])) {
        return true;
    }

    return false;
}

/**
 * Normalize a path to not contain dots & multiple slashes
 *
 * @param string $path
 * @return string false
 */
public function normalizePath($path)
{
    if (DIRECTORY_SEPARATOR !== '/') {
        // convert to / for OSes that use other separators
        $path = str_replace(DIRECTORY_SEPARATOR, '/', $path);
    }
    $res = array();
    foreach (explode("/", $path) as $component) {
        if (empty($component)) {
            continue;
        }
        if ($component === '.') {
            continue;
        }
        if ($component === '..') {
            // this is not allowed, bail
            return false;
        }
        $res[] = $component;
    }

    return implode("/", $res);
}

