public function scanManifest($manifestPath)
{
    $issues = array();
    if (!file_exists($manifestPath)) {
        $this->issues['manifest'][$manifestPath] = translate('ML_NO_MANIFEST');
        return $issues;
    }
    $fileIssues = $this->scanFile($manifestPath);
